// Classify a Telegram reply to a review letter. Letters start with one of
// NEEDS YOU (escalation: expects one decision letter, or continue to take
// the brief's recommendation), PASS or REVISE (advise mode: continue
// re-queues the project). Trust nothing: validate everything.
const msg = $json.message || {};
const orig = (msg.reply_to_message && msg.reply_to_message.text) || '';
const firstLine = (orig.split('\n')[0] || '').trim();
const fm = firstLine.match(/^(NEEDS YOU|PASS|REVISE)\s+([a-z0-9-]+)$/i);
const kind = fm ? fm[1].toUpperCase() : '';
const repo = fm ? fm[2].toLowerCase() : '';
const reply = (msg.text || '').trim();

// A decision is exactly one letter, optionally with trailing . ) or !
// The old first-letter-of-anything rule made "continue" read as C.
const lm = reply.match(/^([A-Za-z])[.)!]?$/);
const singleLetter = lm ? lm[1].toUpperCase() : '';
const go = /^(go|continue|cont|carry on|keep going|y|yes|ok|okay|next|proceed)[.!]?$/i.test(reply);

// Option letters the escalation brief actually offered ("A. ..." lines).
const offered = [];
const optRe = /^\s*([A-Z])\.\s/gm;
let om;
while ((om = optRe.exec(orig)) !== null) {
  if (!offered.includes(om[1])) offered.push(om[1]);
}

let mode = '', letter = '', viaRecommendation = false, fixPrompt = '';
if (kind === 'NEEDS YOU') {
  if (singleLetter && (offered.length === 0 || offered.includes(singleLetter))) {
    mode = 'decision';
    letter = singleLetter;
  } else if (go) {
    const rm = orig.match(/Recommendation:[^\n]*?\b([A-Z])\b/);
    if (rm && (offered.length === 0 || offered.includes(rm[1]))) {
      mode = 'decision';
      letter = rm[1];
      viaRecommendation = true;
    }
  }
} else if (kind === 'PASS' && go) {
  mode = 'requeue';
} else if (kind === 'REVISE' && go) {
  const fxm = orig.match(/Fix prompt \(queued for next session\):\s*\n([\s\S]+)$/);
  fixPrompt = fxm ? fxm[1].trim() : '';
  if (fixPrompt === '(missing)') fixPrompt = '';
  mode = 'requeue_fix';
}

const valid = /^[a-z0-9-]+$/.test(repo) && mode !== '';
const date = new Date().toLocaleDateString('en-CA', { timeZone: 'Europe/London' });
return [{ json: {
  repo: repo, kind: kind, mode: mode, letter: letter,
  viaRecommendation: viaRecommendation, fixPrompt: fixPrompt,
  valid: valid, briefText: orig, date: date,
  chatId: (msg.chat && msg.chat.id) || null,
  replyToId: msg.message_id || null
} }];

// Decode the project file, prepend the right log line, flip any in-flight
// status to queued, bump updated, and decide whether a prompt mint is
// needed. The Next prompt block itself is replaced later, in Finalize.
const ex = $('Extract').first().json;
const gh = $json;
const repo = ex.repo;
const date = ex.date;
const mode = ex.mode;

const raw = Buffer.from(String(gh.content || '').replace(/\s/g, ''), 'base64').toString('utf8');

let logLine;
if (mode === 'decision') {
  logLine = '- ' + date + ': Human decision via Telegram: ' + ex.letter +
    (ex.viaRecommendation ? ' (continue accepted the recommendation)' : '');
} else if (mode === 'requeue') {
  logLine = '- ' + date + ': Pass acknowledged via Telegram: continue with the already-minted prompt.';
} else {
  logLine = '- ' + date + ': Revise accepted via Telegram: fix prompt queued.';
}

let edited = raw.replace(/(##[ \t]*Log[^\n]*\n+)/, function (m) { return m + logLine + '\n'; });
if (edited === raw) {
  edited = raw.replace(/\s+$/, '') + '\n\n## Log\n\n' + logLine + '\n';
}
// queued is the state the runner fires on. Flip whatever in-flight state
// the file is in, but never resurrect done or icebox from a stray reply.
edited = edited.replace(/^status:[ \t]*(escalated|review|running)[ \t]*$/m, 'status: queued');
edited = edited.replace(/^updated:.*$/m, 'updated: ' + date);

// Autonomy and Vision steer the confirmation text and the minter.
const autonomyLoop = /^autonomy:[ \t]*loop[ \t]*$/m.test(raw);
const vm = raw.match(/##[ \t]*Vision[ \t]*\n([\s\S]*?)(?=\n##[ \t]|$)/);
const vision = vm ? vm[1].trim() : '';

const needsMint = mode === 'decision';
let request = null;
if (needsMint) {

const SYSTEM = "You mint the next starting prompt for one project in a personal \"legwork\" work queue. A human has just resolved an escalation by choosing one lettered option. Your job is to write the prompt that the next work session starts from.\n\nOutput ONLY the prompt text. No preamble, no explanation, no surrounding code fences.\n\nRules for the prompt you write:\n- Assume a cold start with no loaded context. Open by pointing at standing context, for example \"Read PROJECT.md and the last three log entries in legwork/projects/<file>.\" Use the real project file name.\n- Exactly one task, small enough to finish in a single sitting. If the chosen option implies a large effort, cut it down to the first concrete step and leave the rest implied.\n- Include a \"Done when:\" line with a concrete, verifiable finish line.\n- End with exactly: \"Final step: run /wrap to update the tracker and mint the next prompt.\"\n- Keep the whole prompt under 15 lines.\n- Plain, direct prose. No em dashes anywhere.\n- If the project is not a Claude coding task (a decision, a call, an errand), write the next human action instead and open the prompt with \"Human action, not a Claude session.\"";
  const userContent =
    'Project file: projects/' + repo + '.md\n\n' +
    (vision ? 'Project vision, the standing brief the prompt must serve:\n' + vision + '\n\n' : '') +
    'The human reviewed an escalation for this project and replied with a single ' +
    'decision letter: ' + ex.letter + '\n\n' +
    'The escalation brief that was sent to them was:\n\n' + ex.briefText + '\n\n' +
    'Write the replacement Next prompt that carries out the chosen option (' + ex.letter +
    '). Output only the prompt text, no preamble, no code fences.';
  request = {
    model: 'claude-sonnet-4-6',
    max_tokens: 1024,
    system: SYSTEM,
    messages: [{ role: 'user', content: userContent }]
  };
}

return [{ json: {
  repo: repo, letter: ex.letter, date: date, mode: mode,
  viaRecommendation: ex.viaRecommendation, fixPrompt: ex.fixPrompt,
  needsMint: needsMint, autonomyLoop: autonomyLoop,
  sha: gh.sha, contentEdited: edited,
  chatId: ex.chatId, replyToId: ex.replyToId,
  request: request
} }];

// Assemble the final file body. decision: install the minted prompt, or a
// marker when the mint failed. requeue: keep the existing block untouched.
// requeue_fix: install the fix prompt lifted from the revise letter, or a
// marker if it could not be read. Never leave a stale brief in place.
const bw = $('Build write-back').first().json;
let body = bw.contentEdited;
const repo = bw.repo;
const letter = bw.letter;
const date = bw.date;
const mode = bw.mode;
const fireNote = bw.autonomyLoop
  ? ' The runner will fire it within minutes.'
  : ' Copy the prompt off the dashboard or /resume when ready.';

function setPromptBlock(newBlock) {
  body = body.replace(/(##[ \t]*Next prompt[ \t]*\n+)```[\s\S]*?```/,
    function (m, p1) { return p1 + newBlock; });
}

let confirmText = '';
if (mode === 'requeue') {
  confirmText = 'Queued ' + repo + ' with the already-minted prompt.' + fireNote;
} else if (mode === 'requeue_fix') {
  const fix = (bw.fixPrompt || '').replace(/```[a-zA-Z]*\n?/g, '').replace(/```/g, '').trim();
  if (fix) {
    setPromptBlock('```text\n' + fix + '\n```');
    confirmText = 'Queued ' + repo + ': revise accepted, fix prompt installed.' + fireNote;
  } else {
    setPromptBlock('```text\nPROMPT NEEDED. A revise was accepted on ' + date +
      ' but its fix prompt could not be read from the letter. Run /resume ' + repo +
      ' to mint a fresh prompt.\n```');
    confirmText = 'Queued ' + repo + ': revise accepted, but the fix prompt could not be read (run /resume ' + repo + ').';
  }
} else {
  let minted = '';
  try {
    const blocks = $json.content || [];
    minted = blocks.filter(function (b) { return b.type === 'text'; })
                   .map(function (b) { return b.text; }).join('\n').trim();
  } catch (e) { minted = ''; }
  minted = minted.replace(/```[a-zA-Z]*\n?/g, '').replace(/```/g, '').trim();
  const via = bw.viaRecommendation ? ' (continue took the recommendation)' : '';
  if (minted) {
    setPromptBlock('```text\n' + minted + '\n```');
    confirmText = 'Queued ' + repo + ': decision ' + letter + via + ' logged, next prompt minted.' + fireNote;
  } else {
    setPromptBlock('```text\nPROMPT NEEDED. Decision ' + letter + ' was logged on ' + date +
      ' and status set to queued, but the next prompt could not be minted automatically. ' +
      'Run /resume ' + repo + ' to mint a fresh prompt.\n```');
    confirmText = 'Logged ' + repo + ': decision ' + letter + via +
      ' recorded and status set to queued, but the next prompt needs minting (run /resume ' + repo + ').';
  }
}

const contentB64 = Buffer.from(body, 'utf8').toString('base64');
const commitMessage = mode === 'decision'
  ? 'legwork: reply capture, decision ' + letter + ' on ' + repo
  : 'legwork: reply capture, continue on ' + repo;

return [{ json: {
  repo: repo, letter: letter, mode: mode, sha: bw.sha,
  contentB64: contentB64, commitMessage: commitMessage,
  chatId: bw.chatId, replyToId: bw.replyToId, confirmText: confirmText
} }];

// Non-reply messages land here: slash commands drive the queue from the
// phone. Anything that is not a command is ignored without a reply.
const msg = $json.message || {};
const text = (msg.text || '').trim();
if (!text.startsWith('/')) return [];

const m = text.match(/^\/([a-zA-Z]+)(?:@\w+)?\s*([\s\S]*)$/);
const cmd = m ? m[1].toLowerCase() : '';
const rest = m ? m[2].trim() : '';
const date = new Date().toLocaleDateString('en-CA', { timeZone: 'Europe/London' });
const chatId = (msg.chat && msg.chat.id) || null;
const replyToId = msg.message_id || null;

const HELP = 'Legwork commands:\n' +
  '/board  every project by status\n' +
  '/show <project>  status, last log, next prompt\n' +
  '/fire <project>  queue one session (one-shot for non-loop projects)\n' +
  '/loop <project>  grant standing autonomy (needs a Vision)\n' +
  '/prompt <project> <text>  mint and install the next prompt, queued\n' +
  '/pause and /resume  stop and restart the runner\n' +
  'Replying to a review letter works as before.';

function out(extra) {
  const base = { cmd: cmd, date: date, chatId: chatId, replyToId: replyToId, repo: '', text: '' };
  for (const k in extra) base[k] = extra[k];
  return [{ json: base }];
}

if (cmd === 'board' || cmd === 'status') return out({ cmd: 'board', route: 'board' });
if (cmd === 'pause' || cmd === 'resume') return out({ route: 'pause' });
if (cmd === 'help' || cmd === 'start') return out({ route: 'reply', replyText: HELP });

if (cmd === 'show' || cmd === 'fire' || cmd === 'loop' || cmd === 'prompt') {
  const am = rest.match(/^(\S+)\s*([\s\S]*)$/);
  const repo = am ? am[1].toLowerCase().replace(/\.md$/, '') : '';
  const free = am ? am[2].trim() : '';
  if (!/^[a-z0-9-]+$/.test(repo)) {
    return out({ route: 'reply', replyText: 'Give me a project name: /' + cmd + ' <project>. Send /board to see them.' });
  }
  if (cmd === 'prompt' && !free) {
    return out({ route: 'reply', replyText: 'Tell me what the session should do: /prompt ' + repo + ' <what to do>.' });
  }
  return out({ route: 'file', repo: repo, text: free });
}
return out({ route: 'reply', replyText: 'Unknown command /' + cmd + '.\n\n' + HELP });

// Keep real project files: *.md, skip _template and anything not a file.
const picked = [];
for (const item of $input.all()) {
  const f = item.json;
  if (f.type === 'file' && /\.md$/.test(String(f.name || '')) && !String(f.name).startsWith('_')) {
    picked.push({ json: { name: f.name } });
  }
}
return picked;

// One message: every project grouped by what it needs from you.
const ex = $('Parse command').first().json;
const files = $('Pick project files').all();
const bodies = $input.all();

function metaOf(text) {
  const m = {};
  const parts = String(text).split('---');
  if (parts.length >= 3) {
    for (const line of parts[1].trim().split('\n')) {
      const i = line.indexOf(':');
      if (i > 0) m[line.slice(0, i).trim()] = line.slice(i + 1).trim();
    }
  }
  return m;
}
function age(updated) {
  const t = Date.parse(String(updated || '').slice(0, 10));
  if (isNaN(t)) return '';
  const d = Math.max(0, Math.round((Date.now() - t) / 86400000));
  return ' (' + d + 'd)';
}

const needsYou = [], review = [], running = [], autoQ = [], manualQ = [], blocked = [];
let icebox = 0, done = 0;

for (let i = 0; i < bodies.length; i++) {
  const raw = String(bodies[i].json.data || '');
  const stem = String((files[i] || { json: {} }).json.name || '').replace(/\.md$/, '');
  const meta = metaOf(raw);
  const status = (meta.status || 'queued').toLowerCase();
  const label = stem + age(meta.updated);
  if (status === 'icebox') { icebox++; continue; }
  if (status === 'done') { done++; continue; }
  if (meta.blocked_on) { blocked.push(stem + ' (' + meta.blocked_on.slice(0, 40) + ')'); continue; }
  if (status === 'escalated') { needsYou.push(label); continue; }
  if (status === 'review') { review.push(label); continue; }
  if (status === 'running') { running.push(label); continue; }
  const pm = raw.match(/##\s*Next prompt[\s\S]*?```[a-zA-Z]*\n([\s\S]*?)```/);
  const prompt = pm ? pm[1].trim() : '';
  const marker = !prompt || /^(Human action|DECISION NEEDED|PROMPT NEEDED)/.test(prompt);
  const loops = (meta.autonomy || '').toLowerCase() === 'loop' && /^##[ \t]*Vision[ \t]*$/m.test(raw);
  const oneShot = !!meta.fire_once;
  let tag = '';
  if (marker) tag = ' (needs a prompt)';
  else if (oneShot) tag = ' (one-shot pending)';
  if ((loops || oneShot) && !marker) autoQ.push(stem + tag);
  else manualQ.push(stem + tag);
}

const lines = ['Legwork board ' + ex.date];
if (needsYou.length) lines.push('NEEDS YOU: ' + needsYou.join(', '));
if (review.length) lines.push('In review: ' + review.join(', '));
if (running.length) lines.push('Running: ' + running.join(', '));
if (autoQ.length) lines.push('Queued, fires on its own: ' + autoQ.join(', '));
if (manualQ.length) lines.push('Queued, waiting on you: ' + manualQ.join(', '));
if (blocked.length) lines.push('Blocked: ' + blocked.join(', '));
lines.push('Icebox ' + icebox + ', done ' + done + '.');
lines.push('/show <project> for detail, /fire <project> to run one.');

return [{ json: { replyText: lines.join('\n'), chatId: ex.chatId, replyToId: ex.replyToId } }];

// Act on /show, /fire, /loop and /prompt against the fetched project file.
// Reads are answered directly; writes hand contentEdited to the PUT.
const ex = $('Parse command').first().json;
const gh = $json;
const raw = Buffer.from(String(gh.content || '').replace(/\s/g, ''), 'base64').toString('utf8');
const date = ex.date, repo = ex.repo, cmd = ex.cmd;

function metaOf(text) {
  const m = {};
  const parts = String(text).split('---');
  if (parts.length >= 3) {
    for (const line of parts[1].trim().split('\n')) {
      const i = line.indexOf(':');
      if (i > 0) m[line.slice(0, i).trim()] = line.slice(i + 1).trim();
    }
  }
  return m;
}
const meta = metaOf(raw);
const status = (meta.status || 'queued').toLowerCase();
const hasVision = /^##[ \t]*Vision[ \t]*$/m.test(raw);
const autonomyLoop = (meta.autonomy || '').toLowerCase() === 'loop';
const pm = raw.match(/##\s*Next prompt[\s\S]*?```[a-zA-Z]*\n([\s\S]*?)```/);
const prompt = pm ? pm[1].trim() : '';
const marker = !prompt || /^(Human action|DECISION NEEDED|PROMPT NEEDED)/.test(prompt);
const fires = autonomyLoop && hasVision;

function reply(text) {
  return [{ json: { needsPut: false, needsMint: false, replyText: text, chatId: ex.chatId, replyToId: ex.replyToId } }];
}
function addLog(body, line) {
  const w = body.replace(/(##[ \t]*Log[^\n]*\n+)/, function (mm) { return mm + line + '\n'; });
  return w === body ? body.replace(/\s+$/, '') + '\n\n## Log\n\n' + line + '\n' : w;
}
function bump(body) { return body.replace(/^updated:.*$/m, 'updated: ' + date); }

if (cmd === 'show') {
  const lm = raw.match(/##[ \t]*Log[^\n]*\n+([\s\S]*?)(?=\n##[ \t]|$)/);
  const logTail = lm ? lm[1].trim().split('\n').slice(0, 3).join('\n') : '(no log)';
  let p = prompt || '(no prompt)';
  if (p.length > 2200) p = p.slice(0, 2200) + '\n[truncated]';
  const head = [repo + ': ' + status + ', updated ' + (meta.updated || '?')];
  if (meta.blocked_on) head.push('Blocked on: ' + meta.blocked_on);
  if (autonomyLoop) head.push('Autonomy: loop' + (hasVision ? '' : ' (but no Vision, the runner refuses it)'));
  if (meta.fire_once) head.push('One-shot fire pending (' + meta.fire_once + ')');
  return reply(head.join('\n') + '\n\nLast log:\n' + logTail + '\n\nNext prompt:\n' + p);
}

if (status === 'done' || status === 'icebox') {
  return reply(repo + ' is ' + status + '; /' + cmd + ' never resurrects it. Reopen it at the desk.');
}

if (cmd === 'fire') {
  if (meta.blocked_on) return reply(repo + ' is blocked_on: ' + meta.blocked_on + '. Clear the blocker first.');
  if (status === 'running') return reply(repo + ' is running right now; firing again would double up. Wait for its letter.');
  if (marker) return reply(repo + ' has no fireable prompt. Send /prompt ' + repo + ' <what to do> first.');
  if (status === 'queued' && fires && !meta.fire_once) {
    return reply(repo + ' is already queued and fires on its own on the next tick.');
  }
  let edited = raw.replace(/^status:[ \t]*(escalated|review)[ \t]*$/m, 'status: queued');
  const oneShot = !fires;
  if (oneShot && !meta.fire_once) edited = edited.replace(/\n---/, '\nfire_once: ' + date + '\n---');
  edited = bump(addLog(edited, '- ' + date + ': Fired via Telegram (/fire' + (oneShot ? ', one-shot' : '') + ').'));
  return [{ json: { needsPut: true, needsMint: false, cmd: cmd, repo: repo, date: date, sha: gh.sha,
    contentEdited: edited, request: null,
    confirmText: 'Queued ' + repo + (oneShot ? ' for one session' : '') + '. The runner fires it within 5 minutes.',
    chatId: ex.chatId, replyToId: ex.replyToId } }];
}

if (cmd === 'loop') {
  if (autonomyLoop) return reply(repo + ' already has autonomy: loop.');
  if (!hasVision) return reply(repo + ' has no Vision section, so the runner would refuse it. Run /vision ' + repo + ' at the desk first; autonomy needs its standing brief.');
  let edited = raw.replace(/\n---/, '\nautonomy: loop\n---');
  edited = bump(addLog(edited, '- ' + date + ': Autonomy granted via Telegram (/loop).'));
  const tail = (status === 'queued' && !marker)
    ? ' It is queued, so the runner fires it on the next tick.'
    : ' It fires whenever it is next queued.';
  return [{ json: { needsPut: true, needsMint: false, cmd: cmd, repo: repo, date: date, sha: gh.sha,
    contentEdited: edited, request: null,
    confirmText: 'Granted autonomy: loop to ' + repo + '.' + tail,
    chatId: ex.chatId, replyToId: ex.replyToId } }];
}

if (cmd === 'prompt') {
  if (status === 'running') return reply(repo + ' is running; its wrap would overwrite a new prompt. Wait for the letter.');
  let edited = raw.replace(/^status:[ \t]*(escalated|review)[ \t]*$/m, 'status: queued');
  edited = bump(addLog(edited, '- ' + date + ': Prompt set via Telegram (/prompt).'));
  const vm = raw.match(/##[ \t]*Vision[ \t]*\n([\s\S]*?)(?=\n##[ \t]|$)/);
  const vision = vm ? vm[1].trim() : '';
  const lm2 = raw.match(/##[ \t]*Log[^\n]*\n+([\s\S]*?)(?=\n##[ \t]|$)/);
  const logTail = lm2 ? lm2[1].trim().split('\n').slice(0, 3).join('\n') : '';
  const SYSTEM = "You mint the next starting prompt for one project in a personal \"legwork\" work queue. The human has just sent, from their phone, a short instruction for what the next work session should do. Your job is to turn it into the prompt that session starts from.\n\nOutput ONLY the prompt text. No preamble, no explanation, no surrounding code fences.\n\nRules for the prompt you write:\n- Assume a cold start with no loaded context. Open by pointing at standing context, for example \"Read PROJECT.md and the last three log entries in legwork/projects/<file>.\" Use the real project file name.\n- Exactly one task, small enough to finish in a single sitting. If the instruction implies a large effort, cut it down to the first concrete step and leave the rest implied.\n- Include a \"Done when:\" line with a concrete, verifiable finish line.\n- End with exactly: \"Final step: run /wrap to update the tracker and mint the next prompt.\"\n- Keep the whole prompt under 15 lines.\n- Plain, direct prose. No em dashes anywhere.\n- If the project is not a Claude coding task (a decision, a call, an errand), write the next human action instead and open the prompt with \"Human action, not a Claude session.\"";
  const userContent = 'Project file: projects/' + repo + '.md\n\n' +
    (vision ? 'Project vision, the standing brief the prompt must serve:\n' + vision + '\n\n' : '') +
    (logTail ? 'Recent log entries, newest first:\n' + logTail + '\n\n' : '') +
    'The human wants the next session to do this:\n\n' + ex.text + '\n\n' +
    'Write the Next prompt that carries this out. Output only the prompt text, no preamble, no code fences.';
  const request = { model: 'claude-sonnet-4-6', max_tokens: 1024, system: SYSTEM,
    messages: [{ role: 'user', content: userContent }] };
  const fireNote = fires ? ' The runner fires it within minutes.' : ' Send /fire ' + repo + ' to run it.';
  return [{ json: { needsPut: true, needsMint: true, cmd: cmd, repo: repo, date: date, sha: gh.sha,
    contentEdited: edited, request: request,
    confirmText: 'Queued ' + repo + ' with a freshly minted prompt.' + fireNote,
    chatId: ex.chatId, replyToId: ex.replyToId } }];
}

return reply('Unhandled command /' + cmd + '.');

// Assemble the final body for the PUT. /prompt installs the minted prompt,
// or a PROMPT NEEDED marker when the mint failed; /fire and /loop pass
// their edited body straight through.
const ap = $('Apply command').first().json;
let body = ap.contentEdited;
let confirmText = ap.confirmText;
if (ap.needsMint) {
  let minted = '';
  try {
    const blocks = $json.content || [];
    minted = blocks.filter(function (b) { return b.type === 'text'; })
                   .map(function (b) { return b.text; }).join('\n').trim();
  } catch (e) { minted = ''; }
  minted = minted.replace(/```[a-zA-Z]*\n?/g, '').replace(/```/g, '').trim();
  const block = minted
    ? '```text\n' + minted + '\n```'
    : '```text\nPROMPT NEEDED. A /prompt mint failed on ' + ap.date + '. Send /prompt ' + ap.repo + ' again or run /resume ' + ap.repo + ' at the desk.\n```';
  body = body.replace(/(##[ \t]*Next prompt[ \t]*\n+)```[\s\S]*?```/, function (m, p1) { return p1 + block; });
  if (!minted) confirmText = ap.repo + ': the prompt mint FAILED; a PROMPT NEEDED marker was installed. Send /prompt again.';
}
return [{ json: { repo: ap.repo, sha: ap.sha,
  contentB64: Buffer.from(body, 'utf8').toString('base64'),
  commitMessage: 'legwork: telegram /' + ap.cmd + ' on ' + ap.repo,
  chatId: ap.chatId, replyToId: ap.replyToId, confirmText: confirmText } }];

// /pause commits the tracked .runner-pause-remote flag; /resume deletes
// it. The runner checks the flag at tick start and again after its pull.
const ex = $('Parse command').first().json;
const sha = $json.sha || '';
function reply(text) {
  return [{ json: { hasOp: false, replyText: text, chatId: ex.chatId, replyToId: ex.replyToId } }];
}
if (ex.cmd === 'pause') {
  if (sha) return reply('Runner is already paused. Send /resume to lift it.');
  return [{ json: { hasOp: true, method: 'PUT',
    body: { message: 'legwork: telegram /pause',
      content: Buffer.from('Paused via Telegram on ' + ex.date + '\n', 'utf8').toString('base64'),
      branch: 'main' },
    confirmText: 'Runner paused: nothing fires until you send /resume.',
    chatId: ex.chatId, replyToId: ex.replyToId } }];
}
if (!sha) return reply('Runner is not paused from here. A local .runner-pause, if one exists, can only be deleted at the desk.');
return [{ json: { hasOp: true, method: 'DELETE',
  body: { message: 'legwork: telegram /resume', sha: sha, branch: 'main' },
  confirmText: 'Runner resumed: eligible queued projects fire on the next tick.',
  chatId: ex.chatId, replyToId: ex.replyToId } }];
